mapper.insert:

	SELECT 'MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIE_PK.NEXTVAL, 6, '0')
	  FROM DUAL

INSERT INTO MOVIE
 (MOVIE_ID
, POSTER_URL
, TITLE
, MOVIE_RATING
, OPEN_DATE
, OPEN_COUNTRY
, RUNNING_TIME
, INTRODUCE
, SYNOPSIS
, ORIGINAL_TITLE
, STATE
, LANGUAGE
, BUDGET
, PROFIT) VALUES
 (#{movieId}
, #{title} || 'URL'
, #{title}
, #{movieRating}
, TO_DATE(#{openDate}, 'YYYY-MM-DD hh:mi:ss')
, #{openCountry}
, #{runningTime}
, #{introduce}
, #{synopsis}
, #{originalTitle}
, #{state}
, #{language}
, #{budget}
, #{profit})
